        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int S = sc.nextInt();
            long[][] A = new long[N][M];
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    A[i][j] = sc.nextLong();
                }
            }
            long[][] prefixSum = new long[N + 1][M + 1];
            for (int i = 0; i <= N; i++) {
                for (int j = 0; j <= M; j++) {
                    prefixSum[i][j] = 0;
                }
            }
            for (int i = 1; i <= N; i++) {
                for (int j = 1; j <= M; j++) {
                    prefixSum[i][j] = prefixSum[i - 1][j] + prefixSum[i][j - 1] - prefixSum[i - 1][j - 1] + A[i - 1][j - 1];
                }
            }
            long count = 0;
            for (int i = 1; i <= N; i++) {
                for (int j = 1; j <= M; j++) {
                    for (int k = i; k <= N; k++) {
                        for (int l = j; l <= M; l++) {
                            long sum = prefixSum[k][l] - prefixSum[k][j - 1] - prefixSum[i - 1][l] + prefixSum[i - 1][j - 1];
                            if (sum <= S) {
                                count++;
                            }
                        }
                    }
                }
            }
            System.out.println(count);
        }
    }
}

